settings.custom_liquid:
{%- assign cta_label = 'Comparer les matelas' -%}
{%- assign cta_url = '#comparateur' -%}

{%- assign title_html = 'TEDIBER<br>OU EMMA ?' -%}
{%- assign subtitle_html = 'Ne croyez plus les promesses,<br>vérifiez les chiffres.' -%}

{%- assign hint_html = 'Et bien plus encore...' -%}

{%- assign top_logo_left_url = 'https://cdn.shopify.com/s/files/1/0903/1342/5220/files/logo_blanc_59147f2f-f476-413b-bcd1-e0e314e8c0fe.svg?v=1762799224' -%}
{%- assign top_logo_right_url = 'https://cdn.shopify.com/s/files/1/0903/1342/5220/files/lp_logo_emma_white.png?v=1751874500' -%}
{%- assign points_brand_logo_url = 'https://cdn.shopify.com/s/files/1/0903/1342/5220/files/logo_blanc_59147f2f-f476-413b-bcd1-e0e314e8c0fe.svg?v=1762799224' -%}
{%- assign visual_image_url = 'https://cdn.shopify.com/s/files/1/0903/1342/5220/files/matelas_hybride_infinite_open.png?v=1772547344' -%}

<section class="tb-compare-hero" role="region" aria-label="Comparateur Tediber et Emma">
  <div class="tb-compare-hero__inner">

    <div class="tb-compare-hero__topbar" aria-label="Tediber versus Emma">
      <div class="tb-compare-hero__topbar-item">
        {% if top_logo_left_url != blank %}
          <img class="tb-compare-hero__brand-logo" src="{{ top_logo_left_url }}" alt="Tediber" loading="eager">
        {% else %}
          <span class="tb-compare-hero__brand-text">tediber</span>
        {% endif %}
      </div>

      <span class="tb-compare-hero__topbar-sep" aria-hidden="true">⚔️</span>

      <div class="tb-compare-hero__topbar-item">
        {% if top_logo_right_url != blank %}
          <img class="tb-compare-hero__brand-logo" src="{{ top_logo_right_url }}" alt="Emma" loading="eager">
        {% else %}
          <span class="tb-compare-hero__brand-text">Emma</span>
        {% endif %}
      </div>
    </div>

    <h1 class="tb-compare-hero__title">
      {{ title_html }}
    </h1>

    <div class="tb-compare-hero__subtitle">
      {{ subtitle_html }}
    </div>

    <div class="tb-compare-hero__mid">
      <div class="tb-compare-hero__visual">
        {% if visual_image_url != blank %}
          <img class="tb-compare-hero__visual-img" src="{{ visual_image_url }}" alt="Comparateur matelas" loading="lazy">
        {% endif %}
      </div>

      <div class="tb-compare-hero__points">
        {% if points_brand_logo_url != blank %}
          <div class="tb-compare-hero__points-brand">
            <img class="tb-compare-hero__points-brand-logo" src="{{ points_brand_logo_url }}" alt="Tediber" loading="lazy">
          </div>
        {% endif %}

        <ul class="tb-compare-hero__list" role="list">
          <li class="tb-compare-hero__item">
            <span class="tb-compare-hero__check" aria-hidden="true">
              <svg viewBox="0 0 24 24" width="24" height="24" focusable="false" aria-hidden="true">
                <circle cx="12" cy="12" r="10" fill="currentColor"></circle>
                <path d="M10.4 15.6 7.7 12.9a1 1 0 1 1 1.4-1.4l1.7 1.7 4.2-4.2a1 1 0 0 1 1.4 1.4l-5 5a1 1 0 0 1-1.4 0Z" fill="#ffffff"></path>
              </svg>
            </span>
            <span class="tb-compare-hero__item-text">MOUSSES 2X PLUS ÉPAISSES</span>
          </li>

          <li class="tb-compare-hero__item">
            <span class="tb-compare-hero__check" aria-hidden="true">
              <svg viewBox="0 0 24 24" width="24" height="24" focusable="false" aria-hidden="true">
                <circle cx="12" cy="12" r="10" fill="currentColor"></circle>
                <path d="M10.4 15.6 7.7 12.9a1 1 0 1 1 1.4-1.4l1.7 1.7 4.2-4.2a1 1 0 0 1 1.4 1.4l-5 5a1 1 0 0 1-1.4 0Z" fill="#ffffff"></path>
              </svg>
            </span>
            <span class="tb-compare-hero__item-text">JUSQU’À 9 COUCHES DE CONFORT</span>
          </li>

          <li class="tb-compare-hero__item">
            <span class="tb-compare-hero__check" aria-hidden="true">
              <svg viewBox="0 0 24 24" width="24" height="24" focusable="false" aria-hidden="true">
                <circle cx="12" cy="12" r="10" fill="currentColor"></circle>
                <path d="M10.4 15.6 7.7 12.9a1 1 0 1 1 1.4-1.4l1.7 1.7 4.2-4.2a1 1 0 0 1 1.4 1.4l-5 5a1 1 0 0 1-1.4 0Z" fill="#ffffff"></path>
              </svg>
            </span>
            <span class="tb-compare-hero__item-text">PLUS DE 10 ANS DE DURÉE DE VIE</span>
          </li>
        </ul>
      </div>
    </div>

    <div class="tb-compare-hero__hint">
      {{ hint_html }}
    </div>

    {% if cta_label != blank and cta_url != blank %}
      <div class="tb-compare-hero__cta">
        <a class="tb-compare-hero__btn" href="{{ cta_url }}">{{ cta_label | escape }}</a>
      </div>
    {% endif %}
  </div>

  <style>
    .tb-compare-hero{
      --tb-bg-1:#010d27;
      --tb-bg-2:#0b1730;
      --tb-ink:rgba(245,238,230,.95);
      --tb-ink-strong:rgba(245,238,230,1);
      --tb-divider:rgba(245,238,230,.18);
      --tb-check:#1f7a55;
      --tb-btn-bg:rgba(245,238,230,.95);
      --tb-btn-ink:#06132b;

      background: radial-gradient(120% 90% at 50% 0%, var(--tb-bg-2) 0%, var(--tb-bg-1) 55%, var(--tb-bg-1) 100%);
      color: var(--tb-ink);
      padding: 28px 16px 36px;
      overflow: hidden;
    }

    .tb-compare-hero__inner{max-width:1100px;margin:0 auto;}

    .tb-compare-hero__topbar{
      display:flex;align-items:center;justify-content:center;gap:14px;
      margin-bottom:18px;opacity:.98;
    }
    .tb-compare-hero__brand-logo{height:22px;width:auto;display:block;}
    .tb-compare-hero__brand-text{font-weight:700;letter-spacing:.02em;text-transform:uppercase;font-size:14px;}
    .tb-compare-hero__topbar-sep{
      display:inline-flex;align-items:center;justify-content:center;
      font-size:18px;line-height:1;opacity:.95;
    }

    .tb-compare-hero__title{
      margin:0 auto 14px;text-align:center;text-transform:uppercase;letter-spacing:.02em;
      font-weight:900;color:var(--tb-ink-strong);
      font-size:clamp(44px,8.2vw,72px);
      line-height:.92;
    }
    .tb-compare-hero__subtitle{
      margin:0 auto 22px;text-align:center;font-weight:800;color:var(--tb-ink);
      font-size:clamp(18px,3.8vw,28px);
      line-height:1.15;max-width:26ch;
    }

    /* ✅ Mobile: image + liste côte à côte */
    .tb-compare-hero__mid{
      display:flex;
      align-items:center;
      justify-content:space-between;
      gap:16px;
      margin-top:6px;
    }
    .tb-compare-hero__visual{
      flex:0 0 46%;
      display:flex;
      justify-content:center;
      align-items:center;
    }
    .tb-compare-hero__visual-img{
      width:100%;
      max-width:260px;
      height:auto;
      display:block;
      filter:drop-shadow(0 18px 38px rgba(0,0,0,.35));
    }
    .tb-compare-hero__points{
      flex:1 1 54%;
      padding-top:6px;
      min-width: 0;
    }

    .tb-compare-hero__points-brand{display:flex;justify-content:center;margin-bottom:12px;}
    .tb-compare-hero__points-brand-logo{height:26px;width:auto;display:block;opacity:.98;}

    .tb-compare-hero__list{margin:0;padding:0;list-style:none;border-top:1px solid var(--tb-divider);}
    .tb-compare-hero__item{
      display:grid;grid-template-columns:30px 1fr;gap:12px;align-items:center;
      padding:18px 0;border-bottom:1px solid var(--tb-divider);
    }
    .tb-compare-hero__check{color:var(--tb-check);display:inline-flex;width:24px;height:24px;align-items:center;justify-content:center;transform:translateY(-1px);}
    .tb-compare-hero__item-text{
      text-transform:uppercase;font-weight:900;letter-spacing:.01em;color:var(--tb-ink-strong);
      font-size:clamp(14px,4.2vw,24px);
      line-height:1.05;
    }

    .tb-compare-hero__hint{
      text-align:center;margin:18px 0 12px;font-weight:800;color:var(--tb-ink);
      font-size:clamp(16px,3.5vw,20px);
    }
    .tb-compare-hero__cta{display:flex;justify-content:center;margin-top:8px;}

    /* ✅ CTA: radius 4px + 16px + Obviously Narrow Bold */
    .tb-compare-hero__btn{
      width:100%;
      max-width:520px;
      background:var(--tb-btn-bg);
      color:var(--tb-btn-ink);
      text-decoration:none;
      text-align:center;

      border-radius:4px;
      padding:16px 18px;

      font-size:16px;
      line-height:1;
      font-weight:800;
      font-family:"Obviously Narrow","Obviously",system-ui,-apple-system,Segoe UI,Roboto,Arial,sans-serif;

      box-shadow:0 10px 30px rgba(0,0,0,.25);
    }
    .tb-compare-hero__btn:focus{outline:2px solid rgba(245,238,230,.75);outline-offset:3px;}

    /* Très petits écrans : on repasse en colonne pour éviter la casse */
    @media (max-width: 360px){
      .tb-compare-hero__mid{flex-direction:column;}
      .tb-compare-hero__visual,
      .tb-compare-hero__points{flex:1 1 auto;width:100%;}
      .tb-compare-hero__visual-img{max-width:320px;}
    }

    @media (min-width: 990px){
      .tb-compare-hero{padding:42px 24px 54px;}
      .tb-compare-hero__subtitle{max-width:40ch;}
      .tb-compare-hero__mid{gap:34px;margin-top:18px;}
      .tb-compare-hero__visual{justify-content:flex-start;flex-basis:40%;}
      .tb-compare-hero__visual-img{max-width:360px;}
      .tb-compare-hero__points-brand{justify-content:flex-start;}
      .tb-compare-hero__hint{margin-top:24px;}
    }
  </style>
</section>
